@namespace Lumeo

@if (Variant == GaugeVariant.Linear)
{
    <div class="@ContainerClass"
         role="meter"
         aria-valuenow="@AriaValueNow.ToString(System.Globalization.CultureInfo.InvariantCulture)"
         aria-valuemin="@Min.ToString(System.Globalization.CultureInfo.InvariantCulture)"
         aria-valuemax="@Max.ToString(System.Globalization.CultureInfo.InvariantCulture)"
         aria-label="@(string.IsNullOrWhiteSpace(Label) ? DisplayValue : Label)"
         @attributes="AdditionalAttributes">
        <svg width="@Size" height="@StrokeWidth" viewBox="0 0 @Size @StrokeWidth"
             xmlns="http://www.w3.org/2000/svg">
            <rect x="0" y="0" width="@Size" height="@StrokeWidth"
                  rx="@(StrokeWidth / 2)"
                  fill="var(--color-@TrackColor)" />
            <rect x="0" y="0" width="@LinearFillWidth" height="@StrokeWidth"
                  rx="@(StrokeWidth / 2)"
                  fill="@ActiveColor"
                  style="transition: width 0.3s ease;" />
        </svg>
        @if (ShowValue)
        {
            <span class="text-xs text-foreground font-medium mt-1 block text-center"
                  style="width: @(Size)px">@LabelBody</span>
        }
    </div>
}
else
{
    @* Radial = 270° arc (gap at bottom), Arc = 180° semicircle (top half) *@
    <div class="@ArcContainerClass"
         role="meter"
         aria-valuenow="@AriaValueNow.ToString(System.Globalization.CultureInfo.InvariantCulture)"
         aria-valuemin="@Min.ToString(System.Globalization.CultureInfo.InvariantCulture)"
         aria-valuemax="@Max.ToString(System.Globalization.CultureInfo.InvariantCulture)"
         aria-label="@(string.IsNullOrWhiteSpace(Label) ? DisplayValue : Label)"
         style="@ArcContainerStyle"
         @attributes="AdditionalAttributes">
        <svg width="@Size" height="@SvgHeight"
             viewBox="0 0 @Size @SvgHeight"
             xmlns="http://www.w3.org/2000/svg"
             style="overflow: visible; display: block;">
            @* Track arc *@
            <circle cx="@CxStr" cy="@CyStr" r="@RadiusStr"
                    fill="none"
                    stroke="var(--color-@TrackColor)"
                    stroke-width="@StrokeWidth"
                    stroke-linecap="round"
                    stroke-dasharray="@TrackDash"
                    stroke-dashoffset="0"
                    transform="rotate(@StartAngleDeg @CxStr @CyStr)" />
            @* Value arc — omitted entirely at 0%: a zero-length dash with a
               round linecap still paints both caps, leaving a dot artifact
               at the arc start when Value == Min. *@
            @if (Percentage > 0)
            {
                <circle cx="@CxStr" cy="@CyStr" r="@RadiusStr"
                        fill="none"
                        stroke="@ActiveColor"
                        stroke-width="@StrokeWidth"
                        stroke-linecap="round"
                        stroke-dasharray="@ValueDash"
                        stroke-dashoffset="0"
                        transform="rotate(@StartAngleDeg @CxStr @CyStr)"
                        style="transition: stroke-dasharray 0.3s ease;" />
            }
        </svg>
        @if (ShowValue)
        {
            <span class="absolute inset-0 flex items-center justify-center text-foreground font-medium pointer-events-none"
                  style="font-size: @(LabelFontSize)px; @LabelOffset">@LabelBody</span>
        }
    </div>
}

@code {
    /// <summary>The current value, clamped to <see cref="Min"/>–<see cref="Max"/> for both the drawn arc/bar and the announced <c>aria-valuenow</c>.</summary>
    [Parameter] public double Value { get; set; }
    /// <summary>Lower bound of the gauge's range (default <c>0</c>).</summary>
    [Parameter] public double Min { get; set; } = 0;
    /// <summary>Upper bound of the gauge's range (default <c>100</c>).</summary>
    [Parameter] public double Max { get; set; } = 100;
    /// <summary>Visual form: <c>Radial</c> (default, 270° arc with a gap at the bottom), <c>Linear</c> (horizontal bar), or <c>Arc</c> (180° semicircle).</summary>
    [Parameter] public GaugeVariant Variant { get; set; } = GaugeVariant.Radial;
    /// <summary>Overall pixel size — width for <c>Linear</c>, diameter for <c>Radial</c>/<c>Arc</c> (default <c>120</c>).</summary>
    [Parameter] public int Size { get; set; } = 120;
    /// <summary>Thickness in pixels of the track/value stroke (default <c>8</c>).</summary>
    [Parameter] public int StrokeWidth { get; set; } = 8;
    /// <summary>Custom text shown in place of the computed percentage, and used as the meter's <c>aria-label</c> when set.</summary>
    [Parameter] public string? Label { get; set; }
    /// <summary>
    /// Custom center/label content — overrides the default text. Drop in a
    /// <c>&lt;NumberTicker&gt;</c> (Lumeo.Motion) here for an animated value, instead
    /// of duplicating count-up animation in core. (#277)
    /// </summary>
    [Parameter] public RenderFragment? LabelContent { get; set; }
    /// <summary>When <c>true</c> (default), renders the value/label text centered on (or below, for <c>Linear</c>) the gauge.</summary>
    [Parameter] public bool ShowValue { get; set; } = true;
    /// <summary>Theme color token (without the <c>--color-</c> prefix) for the filled value stroke/bar when no <see cref="Thresholds"/> match (default <c>"primary"</c>).</summary>
    [Parameter] public string Color { get; set; } = "primary";
    /// <summary>Theme color token (without the <c>--color-</c> prefix) for the unfilled track (default <c>"muted"</c>).</summary>
    [Parameter] public string TrackColor { get; set; } = "muted";
    /// <summary>Optional value-based color overrides, evaluated highest-threshold-first: the first entry whose <c>Value</c> is <c>&lt;=</c> the current <see cref="Value"/> wins, falling back to <see cref="Color"/> when none match.</summary>
    [Parameter] public IReadOnlyList<GaugeThreshold>? Thresholds { get; set; }
    /// <summary>Additional CSS classes merged onto the gauge's root element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the gauge's root <c>role="meter"</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private RenderFragment LabelBody => builder =>
    {
        if (LabelContent is not null) builder.AddContent(0, LabelContent);
        else builder.AddContent(1, DisplayValue);
    };

    private double Percentage => Max > Min
        ? Math.Clamp((Value - Min) / (Max - Min) * 100.0, 0.0, 100.0)
        : 0;

    // aria-valuenow must stay within the declared [Min,Max] range so screen
    // readers announce the same value the meter visually clamps to (#42).
    private double AriaValueNow => Max > Min ? Math.Clamp(Value, Min, Max) : Min;

    private string DisplayValue => string.IsNullOrWhiteSpace(Label)
        ? $"{(int)Math.Round(Percentage)}%"
        : Label!;

    private string ActiveColor
    {
        get
        {
            if (Thresholds is { Count: > 0 })
            {
                foreach (var t in Thresholds.OrderByDescending(t => t.Value))
                {
                    if (Value >= t.Value)
                        return t.Color;
                }
            }
            return $"var(--color-{Color})";
        }
    }

    // ── Geometry helpers (InvariantCulture strings for SVG attributes) ────────
    private double Cx => Size / 2.0;
    private double Cy => Size / 2.0;
    private double Radius => (Size - StrokeWidth) / 2.0;
    private double Circumference => 2 * Math.PI * Radius;

    private string CxStr => Cx.ToString(System.Globalization.CultureInfo.InvariantCulture);
    private string CyStr => Cy.ToString(System.Globalization.CultureInfo.InvariantCulture);
    private string RadiusStr => Radius.ToString(System.Globalization.CultureInfo.InvariantCulture);

    private double ArcDegrees => Variant == GaugeVariant.Arc ? 180.0 : 270.0;
    private double ArcLength => Circumference * ArcDegrees / 360.0;

    private string StartAngleDeg => Variant == GaugeVariant.Arc ? "-180" : "-135";

    private string TrackDash
    {
        get
        {
            var rest = Circumference - ArcLength;
            return $"{ArcLength.ToString(System.Globalization.CultureInfo.InvariantCulture)} {rest.ToString(System.Globalization.CultureInfo.InvariantCulture)}";
        }
    }

    private string ValueDash
    {
        get
        {
            var fill = ArcLength * Percentage / 100.0;
            var rest = Circumference - fill;
            return $"{fill.ToString(System.Globalization.CultureInfo.InvariantCulture)} {rest.ToString(System.Globalization.CultureInfo.InvariantCulture)}";
        }
    }

    private int SvgHeight => Variant == GaugeVariant.Arc
        ? (int)Math.Ceiling(Size / 2.0 + StrokeWidth * 1.5)
        : Size;

    private int LabelFontSize => Math.Max(10, Size / 7);

    /// For the Arc (semicircle) variant, vertically centre the value within the
    /// arc band (apex .. diameter). The label is a `flex items-center` box of
    /// height <see cref="SvgHeight"/>, so a bottom pad of
    /// <c>SvgHeight - (Size+StrokeWidth)/2</c> lands the text centre exactly on
    /// the arc's vertical midpoint <c>Cy - Radius/2 == (Size+StrokeWidth)/4</c>
    /// at any Size/StrokeWidth. The previous `Size*0.3` pad scaled with Size and
    /// pushed the value up near the apex (visibly off-centre).
    private string LabelOffset
    {
        get
        {
            if (Variant != GaugeVariant.Arc) return "";
            var pad = Math.Max(0, SvgHeight - (Size + StrokeWidth) / 2.0);
            return $"padding-bottom: {pad.ToString(System.Globalization.CultureInfo.InvariantCulture)}px;";
        }
    }

    // ── Linear geometry ───────────────────────────────────────────────────────
    private string LinearFillWidth
        => (Size * Percentage / 100.0).ToString(System.Globalization.CultureInfo.InvariantCulture);

    private string ContainerClass
        => Lumeo.Cx.Merge("inline-flex flex-col items-center", Class);

    private string ArcContainerClass
        => Lumeo.Cx.Merge("relative inline-flex items-center justify-center", Class);

    private string ArcContainerStyle
        => $"width: {Size}px; height: {SvgHeight}px;";

    public enum GaugeVariant { Radial, Linear, Arc }

    public record GaugeThreshold(double Value, string Color);
}
